import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const _=JSON.parse('{"title":"盈亏分析操作指南","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/pnl-analysis.md","filePath":"zh-CN/portfolio-and-statements/pnl-analysis.md"}'),l={name:"portfolio-and-statements/pnl-analysis.md"};function n(p,a,s,i,d,h){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="盈亏分析操作指南" tabindex="-1">盈亏分析操作指南 <a class="header-anchor" href="#盈亏分析操作指南" aria-label="Permalink to &quot;盈亏分析操作指南&quot;">​</a></h1><p>盈亏分析页面入口、主要功能及各字段详细解释位置。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><p>以下两种方式均可进入盈亏分析页面：</p><p>方式一：点击资产总览页面的空白处，选择「盈亏分析」</p><p>方式二：长桥 App &gt; 资产 &gt; 全部功能 &gt; 盈亏分析</p><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>盈亏分析页提供全方位的交易盈亏回顾，主要包含以下内容：</p><p>累计盈亏：统计账户因交易或企业行动引起的盈亏总额</p><p>累计收益率：支持简单加权和时间加权两种计算方式</p><p>跑赢指数：与大盘指数的对比情况</p><p>每日收益：按日展示收益明细（收益日历）</p><p>个股收益：各标的盈亏明细，实时更新</p><p>资产变动：资金存取、转仓等资产变动记录</p><h2 id="详细字段解释" tabindex="-1">详细字段解释 <a class="header-anchor" href="#详细字段解释" aria-label="Permalink to &quot;详细字段解释&quot;">​</a></h2><p>各字段的详细定义、计算公式及常见问题，请参考盈亏页面释义文档。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/portfolio-and-statements/盈亏页面释义">盈亏页面释义</a> — 各字段定义与计算公式</li><li><a href="/portfolio-and-statements/持仓成本与盈亏计算">持仓成本与盈亏计算</a> — 成本价与盈亏计算方法</li></ul>',18)])])}const f=t(l,[["render",n]]);export{_ as __pageData,f as default};
